  private static class FlutterClientApiCodec extends StandardMessageCodec {
    public static final FlutterClientApiCodec INSTANCE = new FlutterClientApiCodec();

    private FlutterClientApiCodec() {}

    @Override
    protected Object readValueOfType(byte type, @NonNull ByteBuffer buffer) {
      switch (type) {
        case (byte) 128:
          return BalanceResponse.fromList((ArrayList<Object>) readValue(buffer));
        case (byte) 129:
          return BlockchainErrorMessage.fromList((ArrayList<Object>) readValue(buffer));
        case (byte) 130:
          return CurrencyInfoMessage.fromList((ArrayList<Object>) readValue(buffer));
        default:
          return super.readValueOfType(type, buffer);
      }
    }

    @Override
    protected void writeValue(@NonNull ByteArrayOutputStream stream, Object value) {
      if (value instanceof BalanceResponse) {
        stream.write(128);
        writeValue(stream, ((BalanceResponse) value).toList());
      } else if (value instanceof BlockchainErrorMessage) {
        stream.write(129);
        writeValue(stream, ((BlockchainErrorMessage) value).toList());
      } else if (value instanceof CurrencyInfoMessage) {
        stream.write(130);
        writeValue(stream, ((CurrencyInfoMessage) value).toList());
      } else {
        super.writeValue(stream, value);
      }
    }
  }

